   133→/**
   134→ * Simple fuzzy match scoring
   135→ * Returns a score based on how well the query matches the text
   136→ * Higher score = better match
   137→ */
   138→export function fuzzyMatch(query: string, text: string): number {
   139→  if (!query || !text) return 0;
   140→
   141→  const normalizedQuery = query.toLowerCase().trim();
   142→  const normalizedText = text.toLowerCase();
   143→
   144→  // Exact match gets highest score
   145→  if (normalizedText === normalizedQuery) return 100;
   146→
   147→  // Starts with query gets high score
   148→  if (normalizedText.startsWith(normalizedQuery)) return 90;
   149→
   150→  // Contains query as a word boundary
   151→  const wordBoundaryRegex = new RegExp(`\\b${escapeRegex(normalizedQuery)}`, 'i');
   152→  if (wordBoundaryRegex.test(text)) return 80;
   153→
   154→  // Contains query anywhere
   155→  if (normalizedText.includes(normalizedQuery)) return 70;
   156→
   157→  // Character-by-character fuzzy match
   158→  let queryIndex = 0;
   159→  let consecutiveMatches = 0;
   160→  let maxConsecutive = 0;
   161→  let totalMatches = 0;
   162→
   163→  for (let i = 0; i < normalizedText.length && queryIndex < normalizedQuery.length; i++) {
   164→    if (normalizedText[i] === normalizedQuery[queryIndex]) {
   165→      queryIndex++;
   166→      totalMatches++;
   167→      consecutiveMatches++;
   168→      maxConsecutive = Math.max(maxConsecutive, consecutiveMatches);
   169→    } else {
   170→      consecutiveMatches = 0;
   171→    }
   172→  }
   173→
   174→  // If all query characters were found
   175→  if (queryIndex === normalizedQuery.length) {
   176→    // Score based on match quality
   177→    const matchRatio = totalMatches / normalizedText.length;
   178→    const consecutiveBonus = maxConsecutive / normalizedQuery.length;
   179→    return Math.round(30 + (matchRatio * 20) + (consecutiveBonus * 20));
   180→  }
   181→
   182→  return 0;
   183→}
   184→
   185→function escapeRegex(str: string): string {
   186→  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
   187→}
   188→
   189→/**
   190→ * Score a search result against a query
   191→ */
   192→export function scoreResult(result: SearchResult, query: string): number {
   193→  const titleScore = fuzzyMatch(query, result.title) * 2; // Title weighted 2x
   194→  const subtitleScore = result.subtitle ? fuzzyMatch(query, result.subtitle) : 0;
   195→  const keywordScores = result.keywords?.map(k => fuzzyMatch(query, k)) || [];
   196→  const maxKeywordScore = keywordScores.length > 0 ? Math.max(...keywordScores) : 0;
   197→
   198→  return titleScore + subtitleScore + maxKeywordScore;
   199→}
