   204→export function getNavigationResults(navigate: (path: string) => void): SearchResult[] {
   205→  return NAVIGATION_PAGES.map((page: NavigationPage) => ({
   206→    id: `page-${page.id}`,
   207→    type: 'page' as const,
   208→    title: page.name,
   209→    subtitle: page.description,
   210→    icon: page.icon,
   211→    score: 0,
   212→    keywords: page.keywords,
   213→    action: () => navigate(page.path),
   214→  }));
   215→}
