   217→/**
   218→ * Get external search results for a query
   219→ */
   220→export function getExternalSearchResults(
   221→  query: string,
   222→  preferredEngineId?: string
   223→): SearchResult[] {
   224→  if (!query.trim()) return [];
   225→
   226→  const encodedQuery = encodeURIComponent(query);
   227→
   228→  // Sort engines so preferred one is first
   229→  const sortedEngines = [...SEARCH_ENGINES].sort((a, b) => {
   230→    if (a.id === preferredEngineId) return -1;
   231→    if (b.id === preferredEngineId) return 1;
   232→    return 0;
   233→  });
   234→
   235→  return sortedEngines.map((engine) => ({
   236→    id: `external-${engine.id}`,
   237→    type: 'external' as const,
   238→    title: `Search ${engine.name}`,
   239→    subtitle: `Search for "${query}"`,
   240→    icon: engine.icon,
   241→    score: 10, // Lower priority than internal results
   242→    action: () => {
   243→      const url = engine.urlTemplate.replace('{query}', encodedQuery);
   244→      window.open(url, '_blank', 'noopener,noreferrer');
   245→    },
   246→    metadata: { engineId: engine.id },
   247→  }));
   248→}
