   403→/**
   404→ * Get time tracking entries search results
   405→ */
   406→export function getTimeEntriesResults(navigate: (path: string) => void): SearchResult[] {
   407→  const state = useTimeTrackingStore.getState();
   408→  const entries = state.entries || [];
   409→  const projects = state.projects || [];
   410→
   411→  // Create a project lookup map
   412→  const projectMap = new Map(projects.map((p) => [p.id, p]));
   413→
   414→  return entries.slice(0, 50).map((entry) => { // Limit to 50 recent entries
   415→    const project = entry.projectId ? projectMap.get(entry.projectId) : undefined;
   416→    return {
   417→      id: `time-${entry.id}`,
   418→      type: 'time-entry' as const,
   419→      title: entry.description || 'Time Entry',
   420→      subtitle: project ? `Project: ${project.name}` : undefined,
   421→      icon: '⏱️',
   422→      score: 0,
