   443→    subtitle: faq.answer.slice(0, 100) + (faq.answer.length > 100 ? '...' : ''),
   444→    icon: '❓',
   445→    score: 0,
   446→    keywords: ['faq', 'help', 'question', ...faq.keywords],
   447→    action: () => openSupportModal('help'),
   448→    metadata: {
   449→      fullAnswer: faq.answer,
   450→    },
   451→  }));
   452→}
   453→
   454→/**
   455→ * Get Help topic search results
   456→ */
   457→export function getHelpResults(openSupportModal: (tab: 'report' | 'help' | 'docs') => void): SearchResult[] {
   458→  return HELP_TOPICS.map((topic, index) => ({
   459→    id: `help-${index}`,
   460→    type: 'help' as const,
   461→    title: topic.title,
   462→    subtitle: topic.description,
   463→    icon: '💡',
   464→    score: 0,
   465→    keywords: ['help', ...topic.keywords],
   466→    action: () => {
   467→      // Map topics to appropriate support modal tabs
   468→      if (topic.title.includes('Report')) {
   469→        openSupportModal('report');
   470→      } else if (topic.title.includes('Documentation')) {
   471→        openSupportModal('docs');
   472→      } else {
   473→        openSupportModal('help');
   474→      }
   475→    },
   476→  }));
   477→}
   478→
   479→/**
   480→ * Get all search results from all sources
   481→ */
   482→export function getAllResults(
   483→  navigate: (path: string) => void,
   484→  openSupportModal?: (tab: 'report' | 'help' | 'docs') => void
   485→): SearchResult[] {
   486→  const results: SearchResult[] = [
   487→    ...getNavigationResults(navigate),
   488→    ...getNotesResults(navigate),
   489→    ...getTasksResults(navigate),
   490→    ...getEventsResults(navigate),
   491→    ...getBookmarksResults(),
   492→    ...getDiagramsResults(navigate),
   493→    ...getFormsResults(navigate),
   494→    ...getTimeEntriesResults(navigate),
   495→  ];
   496→
   497→  // Add FAQ and Help results if openSupportModal is provided
   498→  if (openSupportModal) {
   499→    results.push(...getFAQResults(openSupportModal));
   500→    results.push(...getHelpResults(openSupportModal));
   501→  }
   502→
   503→  return results;
   504→}
   505→
   506→/**
   507→ * Search and score all results
   508→ */
   509→export function searchAll(
   510→  query: string,
   511→  navigate: (path: string) => void,
   512→  preferredSearchEngine?: string,
   513→  openSupportModal?: (tab: 'report' | 'help' | 'docs') => void
   514→): SearchResult[] {
   515→  const trimmedQuery = query.trim();
   516→
   517→  // Get all internal results
   518→  const allResults = getAllResults(navigate, openSupportModal);
   519→
   520→  // Score and filter results
   521→  const scoredResults = allResults
   522→    .map((result) => ({
   523→      ...result,
   524→      score: scoreResult(result, trimmedQuery),
   525→    }))
   526→    .filter((result) => result.score > 0)
   527→    .sort((a, b) => b.score - a.score);
   528→
   529→  // Add external search options if there's a query
   530→  const externalResults = trimmedQuery
   531→    ? getExternalSearchResults(trimmedQuery, preferredSearchEngine)
   532→    : [];
   533→
   534→  return [...scoredResults, ...externalResults];
   535→}
   536→
   537→/**
   538→ * Group results by type
   539→ */
   540→export function groupResultsByType(results: SearchResult[]): Map<string, SearchResult[]> {
   541→  const grouped = new Map<string, SearchResult[]>();
   542→
   543→  results.forEach((result) => {
   544→    const existing = grouped.get(result.type) || [];
   545→    grouped.set(result.type, [...existing, result]);
   546→  });
   547→
   548→  return grouped;
   549→}
   550→
   551→/**
   552→ * Get display label for result type
   553→ */
   554→export function getTypeLabel(type: string): string {
   555→  const labels: Record<string, string> = {
   556→    page: 'Navigation',
   557→    note: 'Notes',
   558→    task: 'Tasks',
   559→    event: 'Events',
   560→    bookmark: 'Bookmarks',
   561→    diagram: 'Diagrams',
   562→    form: 'Forms',
   563→    'time-entry': 'Time Entries',
   564→    external: 'Search Web',
   565→    action: 'Actions',
   566→    faq: 'FAQ',
   567→    help: 'Help',
   568→  };
   569→  return labels[type] || type;
   570→}
