     1→/**
     2→ * Analytics Store
     3→ * Manages analytics dashboard preferences and period selection
     4→ */
     5→
     6→import { create } from 'zustand';
     7→import { persist, createJSONStorage } from 'zustand/middleware';
     8→import { createSyncedStorage } from '../lib/syncedStorage';
     9→
    10→export type AnalyticsPeriod = 'today' | 'week' | 'month' | 'year' | 'custom';
    11→
    12→export interface DateRange {
    13→  start: Date;
    14→  end: Date;
    15→}
    16→
    17→interface AnalyticsStore {
    18→  // Period selection
    19→  period: AnalyticsPeriod;
    20→  customRange: DateRange | null;
    21→
    22→  // Actions
    23→  setPeriod: (period: AnalyticsPeriod) => void;
    24→  setCustomRange: (range: DateRange) => void;
    25→
    26→  // Helpers
    27→  getDateRange: () => DateRange;
    28→}
    29→
    30→/**
    31→ * Get date range for a given period
    32→ */
    33→function getDateRangeForPeriod(period: AnalyticsPeriod, customRange: DateRange | null): DateRange {
    34→  const now = new Date();
    35→  const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    36→
    37→  switch (period) {
    38→    case 'today':
    39→      return {
    40→        start: today,
    41→        end: new Date(today.getFullYear(), today.getMonth(), today.getDate(), 23, 59, 59, 999),
    42→      };
    43→
    44→    case 'week':
    45→      // Start of current week (Sunday)
    46→      const weekStart = new Date(today);
    47→      weekStart.setDate(today.getDate() - today.getDay());
    48→      const weekEnd = new Date(weekStart);
    49→      weekEnd.setDate(weekStart.getDate() + 6);
    50→      weekEnd.setHours(23, 59, 59, 999);
    51→      return { start: weekStart, end: weekEnd };
    52→
    53→    case 'month':
    54→      const monthStart = new Date(today.getFullYear(), today.getMonth(), 1);
    55→      const monthEnd = new Date(today.getFullYear(), today.getMonth() + 1, 0, 23, 59, 59, 999);
    56→      return { start: monthStart, end: monthEnd };
    57→
    58→    case 'year':
    59→      const yearStart = new Date(today.getFullYear(), 0, 1);
    60→      const yearEnd = new Date(today.getFullYear(), 11, 31, 23, 59, 59, 999);
    61→      return { start: yearStart, end: yearEnd };
    62→
    63→    case 'custom':
    64→      if (customRange) {
    65→        return customRange;
    66→      }
    67→      // Fallback to this week if no custom range set
    68→      return getDateRangeForPeriod('week', null);
    69→
    70→    default:
    71→      return getDateRangeForPeriod('week', null);
    72→  }
    73→}
    74→
    75→export const useAnalyticsStore = create<AnalyticsStore>()(
    76→  persist(
    77→    (set, get) => ({
    78→      // Initial state
    79→      period: 'week',
