/**
 * Base Widget Component
 *
 * Reusable wrapper for all dashboard widgets
 * Provides loading, error states, refresh button, and consistent styling
 */

import React, { useState, useCallback } from 'react';
import { motion } from 'framer-motion';

export interface BaseWidgetProps {
  title: string;
  icon: string;
  children: React.ReactNode;
  subtitle?: string;
  loading?: boolean;
  error?: string | null;
  onRefresh?: () => void;
  onSettings?: () => void;
  className?: string;
}

export const BaseWidget: React.FC<BaseWidgetProps> = ({
  title,
  icon,
  children,
  subtitle,
  loading = false,
  error = null,
  onRefresh,
  onSettings,
  className = '',
}) => {
  const [isRefreshing, setIsRefreshing] = useState(false);

  const handleRefresh = useCallback(async () => {
    if (!onRefresh || isRefreshing) return;

    setIsRefreshing(true);
    try {
      await onRefresh();
    } finally {
      // Minimum 500ms for visual feedback
      setTimeout(() => setIsRefreshing(false), 500);
    }
  }, [onRefresh, isRefreshing]);

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.2, ease: [0.4, 0, 0.2, 1] }}
      className={`bg-surface-light dark:bg-surface-dark-elevated rounded-card shadow-card p-4 flex flex-col ${className}`}
    >
      {/* Header */}
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <span className="text-2xl">{icon}</span>
          <div>
            <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
              {title}
            </h3>
            {subtitle && (
              <p className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
                {subtitle}
              </p>
            )}
          </div>
        </div>

        <div className="flex items-center gap-2">
          {/* Refresh Button */}
          {onRefresh && (
            <button
              onClick={handleRefresh}
              disabled={isRefreshing || loading}
              className="p-1.5 hover:bg-neutral-100 dark:hover:bg-neutral-800 rounded transition-all duration-standard ease-smooth disabled:opacity-50"
              title="Refresh"
            >
              <span className={`text-lg ${isRefreshing ? 'animate-spin inline-block' : ''}`}>
                🔄
              </span>
            </button>
          )}

          {/* Settings Button */}
          {onSettings && (
            <button
              onClick={onSettings}
              className="p-1.5 hover:bg-neutral-100 dark:hover:bg-neutral-800 rounded transition-all duration-standard ease-smooth"
              title="Settings"
            >
              <span className="text-lg">⚙️</span>
            </button>
          )}
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 flex flex-col">

/**
 * Dashboard Widget Registry
 *
 * Central registry of all available widgets with metadata, API configuration,
 * and lazy-loaded component references.
 *
 * Adding a new widget:
 * 1. Create the widget component in src/widgets/Dashboard/
 * 2. Add an entry to WIDGET_REGISTRY below
 * 3. That's it! The widget will be available in the Widget Manager
 */

import { lazy, type LazyExoticComponent, type FC } from 'react';

export type WidgetCategory = 'core' | 'productivity' | 'news' | 'fun' | 'finance' | 'visual' | 'dev' | 'utility';

// Props interface for widget components
export interface WidgetComponentProps {
  widgetId?: string;
}

export interface WidgetDefinition {
  id: string;
  name: string;
  description: string;
  icon: string; // Emoji icon
  category: WidgetCategory;
  apiUrl?: string;
  apiKey?: string; // 'DEMO_KEY' for APIs that need keys but offer demo access
  requiresAuth?: boolean; // If user needs to provide API key/username
  defaultEnabled: boolean;
  // Lazy-loaded component (automatically generated from id)
  component?: LazyExoticComponent<FC<WidgetComponentProps>>;
}

/**
 * Maps widget ID to its file name in the Dashboard folder
 * Uses convention: widget ID -> PascalCase + "Widget"
 * e.g., "hackernews" -> "HackerNewsWidget"
 */
const WIDGET_FILE_NAMES: Record<string, string> = {
  myday: 'MyDayWidget',
  taskssummary: 'TasksSummaryWidget',
  tasksquickadd: 'TasksQuickAddWidget',
  upcomingevents: 'UpcomingEventsWidget',
  recentnotes: 'RecentNotesWidget',
  quote: 'QuoteWidget',
  crypto: 'CryptoWidget',
  hackernews: 'HackerNewsWidget',
  facts: 'FactsWidget',
  github: 'GitHubWidget',
  joke: 'JokeWidget',
