import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { Risk, RiskState, RiskStatus, RiskCategory } from '../types';

interface RiskStore extends RiskState {
  // Actions
  addRisk: (risk: Omit<Risk, 'id' | 'createdDate' | 'lastReviewed' | 'score'>) => void;
  updateRisk: (id: string, updates: Partial<Risk>) => void;
  deleteRisk: (id: string) => void;
  updateRiskStatus: (id: string, status: RiskStatus) => void;
  linkTaskToRisk: (riskId: string, taskId: string) => void;
  unlinkTaskFromRisk: (riskId: string, taskId: string) => void;
  calculateRiskScore: (probability: number, impact: number) => number;
  getRisksByCategory: (category: RiskCategory) => Risk[];
  getHighRisks: () => Risk[]; // Score >= 15
  getProjectRiskScore: () => number; // Average of all risk scores
  clearAllRisks: () => void;
}

export const useRiskStore = create<RiskStore>()(
  persist(
    (set, get) => ({
      risks: [],

      addRisk: (risk) => {
        const score = get().calculateRiskScore(risk.probability, risk.impact);
        const newRisk: Risk = {
          ...risk,
          id: Date.now().toString(),
          createdDate: new Date().toISOString(),
          lastReviewed: new Date().toISOString(),
          score,
          relatedTasks: risk.relatedTasks || [],
        };
        set((state) => ({
          risks: [...state.risks, newRisk],
        }));
      },

      updateRisk: (id, updates) => {
        set((state) => ({
          risks: state.risks.map((risk) => {
            if (risk.id === id) {
              const updatedRisk = { ...risk, ...updates };
              // Recalculate score if probability or impact changed
              if (updates.probability !== undefined || updates.impact !== undefined) {
                updatedRisk.score = get().calculateRiskScore(
                  updatedRisk.probability,
                  updatedRisk.impact
                );
              }
              updatedRisk.lastReviewed = new Date().toISOString();
              return updatedRisk;
            }
            return risk;
          }),
        }));
      },

      deleteRisk: (id) =>
        set((state) => ({
          risks: state.risks.filter((risk) => risk.id !== id),
        })),

      updateRiskStatus: (id, status) => {
        get().updateRisk(id, { status });
      },

      linkTaskToRisk: (riskId, taskId) =>
        set((state) => ({
          risks: state.risks.map((risk) =>
            risk.id === riskId
              ? {
                  ...risk,
                  relatedTasks: [...risk.relatedTasks, taskId],
                  lastReviewed: new Date().toISOString(),
                }
              : risk
          ),
        })),

import React from 'react';
import { Modal } from './Modal';

interface KeyboardShortcutsHelpProps {
  isOpen: boolean;
  onClose: () => void;
}

/**
 * Keyboard Shortcuts Help Modal
 * Shows all available keyboard shortcuts for the Kanban board
 */
export const KeyboardShortcutsHelp: React.FC<KeyboardShortcutsHelpProps> = ({
  isOpen,
  onClose,
}) => {
  const shortcuts = [
    {
      category: 'Navigation',
      items: [
        { keys: ['J'], description: 'Move down to next task' },
        { keys: ['K'], description: 'Move up to previous task' },
        { keys: ['H'], description: 'Move left to previous column' },
        { keys: ['L'], description: 'Move right to next column' },
      ],
    },
    {
      category: 'Actions',
      items: [
        { keys: ['N'], description: 'Create new task in current column' },
        { keys: ['E'], description: 'Edit selected task' },
        { keys: ['D'], description: 'Delete selected task' },
      ],
    },
    {
      category: 'General',
      items: [
        { keys: ['?'], description: 'Toggle this help menu' },
        { keys: ['Esc'], description: 'Clear selection / Close dialogs' },
      ],
    },
  ];

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="⌨️ Keyboard Shortcuts">
      <div className="space-y-6">
        {shortcuts.map((section) => (
          <div key={section.category}>
            <h4 className="text-sm font-semibold text-accent-primary mb-3 uppercase tracking-wide">
              {section.category}
            </h4>
            <div className="space-y-2">
              {section.items.map((shortcut, index) => (
                <div
                  key={index}
                  className="flex items-center justify-between py-2 border-b border-neutral-lightGray dark:border-neutral-darkGray last:border-0"
                >
                  <span className="text-sm text-gray-700 dark:text-gray-300">
                    {shortcut.description}
                  </span>
                  <div className="flex gap-1">
                    {shortcut.keys.map((key, keyIndex) => (
                      <kbd
                        key={keyIndex}
                        className="px-3 py-1.5 text-xs font-mono font-semibold bg-neutral-paleGray dark:bg-neutral-darkGray text-gray-900 dark:text-white rounded-buttonborder border-neutral-lightGray dark:border-neutral-gray shadow-sm"
                      >
                        {key}
                      </kbd>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}

        <div className="pt-4 border-t border-neutral-lightGray dark:border-neutral-darkGray">
          <p className="text-xs text-gray-500 dark:text-gray-400 italic">
            💡 Tip: Keyboard shortcuts work when you're not typing in an input field.
          </p>
        </div>
      </div>
    </Modal>
  );
};

