/**
 * Command Palette Component
 *
 * Global search and navigation interface, accessible via Ctrl+K (Win/Linux) or Cmd+K (Mac).
 * Provides Spotlight-like universal search across all app data.
 */

import React, { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useNavigate } from 'react-router-dom';
import { Search, X, ExternalLink, ArrowRight } from 'lucide-react';
import { useEscapeKey } from '../../hooks/useEscapeKey';
import { searchAll, groupResultsByType, getTypeLabel } from './searchRegistry';
import { SEARCH_ENGINES } from './types';
import type { SearchResult } from './types';
import { useSettingsStore } from '../../stores/useSettingsStore';

interface CommandPaletteProps {
  isOpen: boolean;
  onClose: () => void;
  /** Callback to open the support modal with a specific tab */
  onOpenSupportModal?: (tab: 'report' | 'help' | 'docs') => void;
}

/**
 * Type icons mapping
 */
const TYPE_ICONS: Record<string, string> = {
  page: '🏠',
  note: '📝',
  task: '✅',
  event: '📅',
  bookmark: '🔗',
  diagram: '📊',
  form: '📋',
  'time-entry': '⏱️',
  external: '🌐',
  action: '⚡',
  faq: '❓',
  help: '💡',
};

export const CommandPalette: React.FC<CommandPaletteProps> = ({ isOpen, onClose, onOpenSupportModal }) => {
  const navigate = useNavigate();
  const inputRef = useRef<HTMLInputElement>(null);
  const listRef = useRef<HTMLDivElement>(null);
  const selectedItemRef = useRef<HTMLButtonElement>(null);

  const [query, setQuery] = useState('');
  const [selectedIndex, setSelectedIndex] = useState(0);

  // Get preferred search engine from settings (default to Google)
  const preferredSearchEngine = useSettingsStore(
    (state) => state.commandPalette?.preferredSearchEngine ?? 'google'
  );

  // Handle escape key
  useEscapeKey({ enabled: isOpen, onEscape: onClose, priority: 10000 });

  // Search results with memoization
  const results = useMemo(() => {
    if (!isOpen) return [];
    return searchAll(query, navigate, preferredSearchEngine, onOpenSupportModal);
  }, [query, isOpen, navigate, preferredSearchEngine, onOpenSupportModal]);

  // Group results by type
  const groupedResults = useMemo(() => {
    return groupResultsByType(results);
  }, [results]);

  // Flatten grouped results for keyboard navigation
  const flatResults = useMemo(() => {
    const flat: SearchResult[] = [];
    groupedResults.forEach((items) => {
      flat.push(...items);
    });
    return flat;
  }, [groupedResults]);

  // Reset state when opening/closing
  useEffect(() => {
    if (isOpen) {
      setQuery('');
      setSelectedIndex(0);
      // Focus input after a short delay to ensure modal is rendered
      setTimeout(() => inputRef.current?.focus(), 50);
    }
  }, [isOpen]);

  // Keep selected item in view
  useEffect(() => {
    selectedItemRef.current?.scrollIntoView({ block: 'nearest' });
  }, [selectedIndex]);

  // Keyboard navigation
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      switch (e.key) {
        case 'ArrowDown':
          e.preventDefault();
          setSelectedIndex((prev) =>
            prev < flatResults.length - 1 ? prev + 1 : 0
          );
          break;
        case 'ArrowUp':
          e.preventDefault();
          setSelectedIndex((prev) =>
            prev > 0 ? prev - 1 : flatResults.length - 1
          );
          break;
        case 'Enter':
          e.preventDefault();
          if (flatResults[selectedIndex]) {
            flatResults[selectedIndex].action();
            onClose();
          }
          break;
        case 'Tab':
          e.preventDefault();
          if (e.shiftKey) {
            setSelectedIndex((prev) =>
              prev > 0 ? prev - 1 : flatResults.length - 1
            );
          } else {
            setSelectedIndex((prev) =>
              prev < flatResults.length - 1 ? prev + 1 : 0
            );
          }
          break;
      }
    },
    [flatResults, selectedIndex, onClose]
  );

  // Handle result click
  const handleResultClick = useCallback(
    (result: SearchResult) => {
      result.action();
      onClose();
    },
    [onClose]
  );

  // Handle backdrop click
  const handleBackdropClick = useCallback(
    (e: React.MouseEvent) => {
      if (e.target === e.currentTarget) {
        onClose();
      }
    },

